"use client";

import { useEffect, useMemo } from "react";
import {
  DndContext,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
} from "@dnd-kit/core";
import { sortableKeyboardCoordinates } from "@dnd-kit/sortable";
import { cn } from "@/lib/utils";
import { Board } from "./parts/board";
import { KanbanDragOverlay } from "./parts/drag-overlay";
import { useDragHandlers } from "./hooks/use-drag-handlers";
import { useKanbanState } from "./hooks/use-kanban-state";
import { useRendererMap } from "./hooks/use-renderer-map";
import { newColumnId, newItemId } from "./lib/ids";
import { DEFAULT_PALETTE } from "./lib/palette";
import { validateData } from "./lib/data";
import type {
  AnyKanbanCardRenderer,
  KanbanBoardProps,
  KanbanColumn,
  KanbanItem,
} from "./types";

export function KanbanBoard({
  renderers,
  data,
  defaultData,
  onChange,
  onItemCreate,
  onItemUpdate,
  onItemDelete,
  onColumnCreate,
  onColumnUpdate,
  onColumnDelete,
  onItemClick,
  onItemMove,
  palette,
  readOnly = false,
  "aria-label": ariaLabel = "Kanban board",
  className,
}: KanbanBoardProps) {
  const [state, dispatch] = useKanbanState({ data, defaultData, onChange });
  const rendererMap = useRendererMap(renderers);
  const palettePinned = useMemo(() => palette ?? DEFAULT_PALETTE, [palette]);

  // Mount-time validation (developer feedback only; doesn't block render).
  useEffect(() => {
    if (renderers.length === 0) {
      console.error(
        "[kanban-board-01] `renderers` prop is required and must contain at least one entry.",
      );
      return;
    }
    const result = validateData(state, renderers);
    if (!result.valid) {
      for (const err of result.errors) {
        console.warn(`[kanban-board-01] ${err}`);
      }
    }
    // Run once per session-equivalent — re-run if renderers change.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [renderers]);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const {
    onDragStart,
    onDragOver,
    onDragEnd,
    onDragCancel,
    activeItem,
    activeRendererId,
  } = useDragHandlers({
    data: state,
    readOnly,
    dispatch,
    onItemMove,
  });

  // Internal handlers translating UI events into reducer actions + consumer callbacks.
  function handleItemCreate(columnId: string, item: KanbanItem) {
    dispatch({ type: "create-item", columnId, item });
    onItemCreate?.(columnId, item);
  }

  function handleItemUpdate(item: KanbanItem) {
    dispatch({ type: "update-item", item });
    onItemUpdate?.(item);
  }

  function handleItemDelete(itemId: string) {
    dispatch({ type: "delete-item", itemId });
    onItemDelete?.(itemId);
  }

  function handleColumnCreate(column: KanbanColumn) {
    dispatch({ type: "create-column", column });
    onColumnCreate?.(column);
  }

  function handleColumnUpdate(column: KanbanColumn) {
    dispatch({ type: "update-column", column });
    onColumnUpdate?.(column);
  }

  function handleColumnDelete(columnId: string) {
    dispatch({ type: "delete-column", columnId });
    onColumnDelete?.(columnId);
  }

  function handleSetColor(columnId: string, color: string | undefined) {
    dispatch({ type: "set-color", columnId, color });
  }

  function handleToggleCollapse(columnId: string) {
    dispatch({ type: "toggle-collapse", columnId });
  }

  if (renderers.length === 0) {
    return (
      <div
        role="region"
        aria-label={ariaLabel}
        className={cn(
          "flex h-full min-h-32 items-center justify-center rounded-md border border-destructive/40 bg-destructive/5 p-6 text-sm text-destructive",
          className,
        )}
      >
        kanban-board-01 requires at least one renderer
      </div>
    );
  }

  // In readOnly mode, skip DnD wiring entirely.
  if (readOnly) {
    return (
      <div
        role="region"
        aria-label={ariaLabel}
        className={cn("relative flex h-full min-h-0 flex-col", className)}
      >
        <Board
          data={state}
          swimlanes={state.swimlanes}
          rendererMap={rendererMap}
          renderers={renderers}
          palette={palettePinned}
          readOnly
          activeRendererId={undefined}
          onItemClick={onItemClick}
          onSetColor={handleSetColor}
          onToggleCollapse={handleToggleCollapse}
        />
      </div>
    );
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDragEnd={onDragEnd}
      onDragCancel={onDragCancel}
    >
      <div
        role="region"
        aria-label={ariaLabel}
        className={cn("relative flex h-full min-h-0 flex-col", className)}
      >
        <Board
          data={state}
          swimlanes={state.swimlanes}
          rendererMap={rendererMap}
          renderers={renderers}
          palette={palettePinned}
          readOnly={false}
          activeRendererId={activeRendererId}
          onItemCreate={onItemCreate ? handleItemCreate : undefined}
          onItemUpdate={onItemUpdate ? handleItemUpdate : undefined}
          onItemDelete={onItemDelete ? handleItemDelete : undefined}
          onItemClick={onItemClick}
          onColumnCreate={onColumnCreate ? handleColumnCreate : undefined}
          onColumnUpdate={onColumnUpdate ? handleColumnUpdate : undefined}
          onColumnDelete={onColumnDelete ? handleColumnDelete : undefined}
          onSetColor={handleSetColor}
          onToggleCollapse={handleToggleCollapse}
        />
      </div>
      <KanbanDragOverlay activeItem={activeItem} rendererMap={rendererMap} />
    </DndContext>
  );
}

// Public helper exported for advanced consumers writing custom inline editors.
export function findRenderer(
  renderers: AnyKanbanCardRenderer[],
  rendererId: string,
): AnyKanbanCardRenderer | undefined {
  return renderers.find((r) => r.id === rendererId);
}

// Re-export ID helpers for consumers building items / columns programmatically.
export { newItemId, newColumnId };

export { KanbanBoard, findRenderer, newColumnId, newItemId } from "./kanban-board-01";
export { kanbanCardRenderer, KanbanCardView } from "./parts/kanban-card";
export { kanbanNoteRenderer, KanbanNoteView } from "./parts/kanban-note";
export { DEFAULT_PALETTE } from "./lib/palette";
export { validateData } from "./lib/data";
export type {
  KanbanBoardProps,
  KanbanCardData,
  KanbanCardRenderer,
  KanbanColumn,
  KanbanData,
  KanbanItem,
  KanbanNoteData,
  KanbanPaletteSwatch,
  KanbanRenderContext,
  KanbanSwimlane,
} from "./types";
export { meta } from "./meta";

import type { ReactNode } from "react";

export type KanbanRenderContext = {
  itemId: string;
  columnId: string;
  swimlaneId?: string;
  isDragging: boolean;
  isLocked: boolean;
};

export type KanbanCardRenderer<TData = unknown> = {
  id: string;
  label: string;
  render: (data: TData, ctx: KanbanRenderContext) => ReactNode;
  newItem?: () => TData;
  editForm?: (
    data: TData,
    onSave: (next: TData) => void,
    onCancel: () => void,
  ) => ReactNode;
  /**
   * Where the kanban-level drag listeners attach.
   * - `"shell"` (default): the entire item is the drag activator (cursor-grab on the whole card).
   * - `"header"`: only a thin grip strip rendered above the item activates dragging; the body
   *    stays fully interactive. Use for renderers that own internal pointer interactions
   *    (inline editors, nested DnD), e.g. the rich-card adapter.
   */
  dragHandle?: "shell" | "header";
};

/**
 * Type-erased renderer used inside the board's registry. The board never reads
 * the data shape — it just hands data to the renderer's render fn — so erasing
 * TData here is sound. Consumers always interact with the typed
 * `KanbanCardRenderer<TData>` surface.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export type AnyKanbanCardRenderer = KanbanCardRenderer<any>;

export type KanbanItem = {
  id: string;
  rendererId: string;
  data: unknown;
  swimlaneId?: string;
  locked?: boolean;
};

export type KanbanColumn = {
  id: string;
  title: string;
  description?: string;
  color?: string;
  collapsed?: boolean;
  items: KanbanItem[];
  allowReorder?: boolean;
  allowIncoming?: boolean;
  allowOutgoing?: boolean;
  acceptsRendererIds?: string[];
  maxItems?: number;
};

export type KanbanSwimlane = {
  id: string;
  title: string;
  description?: string;
  color?: string;
};

export type KanbanData = {
  columns: KanbanColumn[];
  swimlanes?: KanbanSwimlane[];
};

export type KanbanPaletteSwatch = {
  id: string;
  label: string;
  cssVar: string;
};

export type KanbanBoardProps = {
  renderers: AnyKanbanCardRenderer[];

  data?: KanbanData;
  defaultData?: KanbanData;
  onChange?: (next: KanbanData) => void;

  onItemCreate?: (columnId: string, item: KanbanItem) => void;
  onItemUpdate?: (item: KanbanItem) => void;
  onItemDelete?: (itemId: string) => void;
  onColumnCreate?: (draft: Partial<KanbanColumn>) => void;
  onColumnUpdate?: (column: KanbanColumn) => void;
  onColumnDelete?: (columnId: string) => void;

  onItemClick?: (item: KanbanItem) => void;
  onItemMove?: (
    item: KanbanItem,
    from: { columnId: string; swimlaneId?: string },
    to: { columnId: string; swimlaneId?: string },
  ) => void;

  palette?: KanbanPaletteSwatch[];
  readOnly?: boolean;

  "aria-label"?: string;
  className?: string;
};

export type KanbanCardData = {
  title: string;
  description?: string;
  tags?: { label: string; color?: string }[];
  assignees?: { id: string; name: string; avatarUrl?: string }[];
  meta?: { key: string; label: string; value: ReactNode }[];
};

export type KanbanNoteData = {
  title: string;
  body?: string;
  color?: string;
};

export type KanbanAction =
  | { type: "move-item"; itemId: string; toColumnId: string; toIndex: number; toSwimlaneId?: string }
  | { type: "reorder-column"; columnId: string; toIndex: number }
  | { type: "create-item"; columnId: string; item: KanbanItem; index?: number }
  | { type: "update-item"; item: KanbanItem }
  | { type: "delete-item"; itemId: string }
  | { type: "create-column"; column: KanbanColumn; index?: number }
  | { type: "update-column"; column: KanbanColumn }
  | { type: "delete-column"; columnId: string }
  | { type: "toggle-collapse"; columnId: string }
  | { type: "set-color"; columnId: string; color: string | undefined }
  | { type: "replace"; data: KanbanData };

import type {
  AnyKanbanCardRenderer,
  KanbanColumn,
  KanbanData,
  KanbanItem,
} from "../types";

export function findItem(
  data: KanbanData,
  itemId: string,
): { item: KanbanItem; columnId: string; index: number } | null {
  for (const col of data.columns) {
    const idx = col.items.findIndex((it) => it.id === itemId);
    if (idx >= 0) return { item: col.items[idx], columnId: col.id, index: idx };
  }
  return null;
}

export function findColumn(
  data: KanbanData,
  columnId: string,
): { column: KanbanColumn; index: number } | null {
  const idx = data.columns.findIndex((c) => c.id === columnId);
  if (idx < 0) return null;
  return { column: data.columns[idx], index: idx };
}

export function moveItem(
  data: KanbanData,
  itemId: string,
  toColumnId: string,
  toIndex: number,
  toSwimlaneId?: string,
): KanbanData {
  const found = findItem(data, itemId);
  if (!found) return data;

  const movingItem: KanbanItem = {
    ...found.item,
    swimlaneId: toSwimlaneId !== undefined ? toSwimlaneId : found.item.swimlaneId,
  };

  // Remove from source column.
  const stripped: KanbanColumn[] = data.columns.map((c) => {
    if (c.id !== found.columnId) return c;
    return { ...c, items: c.items.filter((it) => it.id !== itemId) };
  });

  // Insert into target column. Auto-expand if target was collapsed
  // (locked contract: "drop on collapsed → expand"; bundled into the move
  // action so it's atomic in both controlled and uncontrolled modes).
  const result = stripped.map((c) => {
    if (c.id !== toColumnId) return c;
    const next = c.items.slice();
    const clamped = Math.max(0, Math.min(toIndex, next.length));
    next.splice(clamped, 0, movingItem);
    return { ...c, items: next, collapsed: c.collapsed ? false : c.collapsed };
  });

  return { ...data, columns: result };
}

export function reorderColumn(
  data: KanbanData,
  columnId: string,
  toIndex: number,
): KanbanData {
  const fromIdx = data.columns.findIndex((c) => c.id === columnId);
  if (fromIdx < 0) return data;
  const cols = data.columns.slice();
  const [removed] = cols.splice(fromIdx, 1);
  const clamped = Math.max(0, Math.min(toIndex, cols.length));
  cols.splice(clamped, 0, removed);
  return { ...data, columns: cols };
}

export function addItem(
  data: KanbanData,
  columnId: string,
  item: KanbanItem,
  index?: number,
): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) => {
      if (c.id !== columnId) return c;
      const next = c.items.slice();
      const at = index === undefined ? next.length : Math.max(0, Math.min(index, next.length));
      next.splice(at, 0, item);
      return { ...c, items: next };
    }),
  };
}

export function updateItem(data: KanbanData, item: KanbanItem): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) => ({
      ...c,
      items: c.items.map((it) => (it.id === item.id ? item : it)),
    })),
  };
}

export function deleteItem(data: KanbanData, itemId: string): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) => ({
      ...c,
      items: c.items.filter((it) => it.id !== itemId),
    })),
  };
}

export function addColumn(
  data: KanbanData,
  column: KanbanColumn,
  index?: number,
): KanbanData {
  const next = data.columns.slice();
  const at = index === undefined ? next.length : Math.max(0, Math.min(index, next.length));
  next.splice(at, 0, column);
  return { ...data, columns: next };
}

export function updateColumn(data: KanbanData, column: KanbanColumn): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) => (c.id === column.id ? column : c)),
  };
}

export function deleteColumn(data: KanbanData, columnId: string): KanbanData {
  return { ...data, columns: data.columns.filter((c) => c.id !== columnId) };
}

export function toggleCollapse(data: KanbanData, columnId: string): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) =>
      c.id === columnId ? { ...c, collapsed: !c.collapsed } : c,
    ),
  };
}

export function setColumnColor(
  data: KanbanData,
  columnId: string,
  color: string | undefined,
): KanbanData {
  return {
    ...data,
    columns: data.columns.map((c) => (c.id === columnId ? { ...c, color } : c)),
  };
}

export type ValidationResult = { valid: boolean; errors: string[] };

export function validateData(
  data: KanbanData,
  renderers: AnyKanbanCardRenderer[],
): ValidationResult {
  const errors: string[] = [];
  const rendererIds = new Set(renderers.map((r) => r.id));
  const swimlaneIds = new Set((data.swimlanes ?? []).map((l) => l.id));
  const colIds = new Set<string>();
  const itemIds = new Set<string>();

  for (const col of data.columns) {
    if (colIds.has(col.id)) errors.push(`Duplicate column id: ${col.id}`);
    colIds.add(col.id);
    for (const item of col.items) {
      if (itemIds.has(item.id)) errors.push(`Duplicate item id: ${item.id}`);
      itemIds.add(item.id);
      if (!rendererIds.has(item.rendererId)) {
        errors.push(`Item ${item.id} references unknown renderer: ${item.rendererId}`);
      }
      if (item.swimlaneId && data.swimlanes && !swimlaneIds.has(item.swimlaneId)) {
        errors.push(`Item ${item.id} references unknown swimlane: ${item.swimlaneId}`);
      }
    }
  }

  return { valid: errors.length === 0, errors };
}

import type { KanbanAction, KanbanData } from "../types";
import {
  addColumn,
  addItem,
  deleteColumn,
  deleteItem,
  moveItem,
  reorderColumn,
  setColumnColor,
  toggleCollapse,
  updateColumn,
  updateItem,
} from "./data";

export function kanbanReducer(state: KanbanData, action: KanbanAction): KanbanData {
  switch (action.type) {
    case "move-item":
      return moveItem(state, action.itemId, action.toColumnId, action.toIndex, action.toSwimlaneId);
    case "reorder-column":
      return reorderColumn(state, action.columnId, action.toIndex);
    case "create-item":
      return addItem(state, action.columnId, action.item, action.index);
    case "update-item":
      return updateItem(state, action.item);
    case "delete-item":
      return deleteItem(state, action.itemId);
    case "create-column":
      return addColumn(state, action.column, action.index);
    case "update-column":
      return updateColumn(state, action.column);
    case "delete-column":
      return deleteColumn(state, action.columnId);
    case "toggle-collapse":
      return toggleCollapse(state, action.columnId);
    case "set-color":
      return setColumnColor(state, action.columnId, action.color);
    case "replace":
      return action.data;
  }
}

import type { KanbanData } from "../types";
import { findColumn, findItem } from "./data";

export type CanDropArgs = {
  data: KanbanData;
  itemId: string;
  fromColumnId: string;
  toColumnId: string;
  fromSwimlaneId?: string;
  toSwimlaneId?: string;
  readOnly: boolean;
};

export function canDrop(args: CanDropArgs): boolean {
  if (args.readOnly) return false;

  const found = findItem(args.data, args.itemId);
  if (!found) return false;
  if (found.item.locked) return false;

  const fromCol = findColumn(args.data, args.fromColumnId)?.column;
  const toCol = findColumn(args.data, args.toColumnId)?.column;
  if (!fromCol || !toCol) return false;

  const sameColumn = args.fromColumnId === args.toColumnId;

  if (sameColumn) {
    if (toCol.allowReorder === false) return false;
  } else {
    if (fromCol.allowOutgoing === false) return false;
    if (toCol.allowIncoming === false) return false;
  }

  if (toCol.acceptsRendererIds && !toCol.acceptsRendererIds.includes(found.item.rendererId)) {
    return false;
  }

  return true;
}

let counter = 0;

function rand() {
  return Math.random().toString(36).slice(2, 8);
}

export function newItemId(): string {
  counter += 1;
  return `item-${rand()}-${counter.toString(36)}`;
}

export function newColumnId(): string {
  counter += 1;
  return `col-${rand()}-${counter.toString(36)}`;
}

export function newSwimlaneId(): string {
  counter += 1;
  return `lane-${rand()}-${counter.toString(36)}`;
}

import type { KanbanPaletteSwatch } from "../types";

export const DEFAULT_PALETTE: KanbanPaletteSwatch[] = [
  { id: "slate", label: "Slate", cssVar: "--muted-foreground" },
  { id: "lime", label: "Lime", cssVar: "--primary" },
  { id: "amber", label: "Amber", cssVar: "--chart-1" },
  { id: "emerald", label: "Emerald", cssVar: "--chart-2" },
  { id: "sky", label: "Sky", cssVar: "--chart-3" },
  { id: "rose", label: "Rose", cssVar: "--destructive" },
];

export function findSwatch(
  palette: KanbanPaletteSwatch[],
  id: string | undefined,
): KanbanPaletteSwatch | undefined {
  if (!id) return undefined;
  return palette.find((s) => s.id === id);
}

export function swatchCssColor(swatch: KanbanPaletteSwatch | undefined): string | undefined {
  if (!swatch) return undefined;
  return `var(${swatch.cssVar})`;
}

"use client";

import { useCallback, useReducer } from "react";
import type { KanbanAction, KanbanData } from "../types";
import { kanbanReducer } from "../lib/reducer";

const EMPTY: KanbanData = { columns: [] };

export function useKanbanState({
  data,
  defaultData,
  onChange,
}: {
  data?: KanbanData;
  defaultData?: KanbanData;
  onChange?: (next: KanbanData) => void;
}): [KanbanData, (action: KanbanAction) => void] {
  const [internal, internalDispatch] = useReducer(kanbanReducer, defaultData ?? EMPTY);

  const isControlled = data !== undefined;
  const state = isControlled ? data : internal;

  const dispatch = useCallback(
    (action: KanbanAction) => {
      const next = kanbanReducer(state, action);
      if (!isControlled) internalDispatch(action);
      onChange?.(next);
    },
    [isControlled, state, onChange],
  );

  return [state, dispatch];
}

"use client";

import { useMemo } from "react";
import type { AnyKanbanCardRenderer } from "../types";

export function useRendererMap(
  renderers: AnyKanbanCardRenderer[],
): Map<string, AnyKanbanCardRenderer> {
  return useMemo(() => {
    const m = new Map<string, AnyKanbanCardRenderer>();
    for (const r of renderers) m.set(r.id, r);
    return m;
  }, [renderers]);
}

"use client";

import { useCallback, useState } from "react";
import type { DragEndEvent, DragStartEvent } from "@dnd-kit/core";
import { findItem } from "../lib/data";
import { canDrop } from "../lib/permissions";
import type { KanbanAction, KanbanData, KanbanItem } from "../types";

type Active =
  | { kind: "item"; item: KanbanItem }
  | { kind: "column"; columnId: string }
  | null;

export function useDragHandlers({
  data,
  readOnly,
  dispatch,
  onItemMove,
}: {
  data: KanbanData;
  readOnly: boolean;
  dispatch: (action: KanbanAction) => void;
  onItemMove?: (
    item: KanbanItem,
    from: { columnId: string; swimlaneId?: string },
    to: { columnId: string; swimlaneId?: string },
  ) => void;
}) {
  const [active, setActive] = useState<Active>(null);

  const onDragStart = useCallback(
    (event: DragStartEvent) => {
      if (readOnly) return;
      const activeData = event.active.data.current as
        | { kind: "item"; columnId: string; swimlaneId?: string; rendererId: string }
        | { kind: "column"; columnId: string }
        | undefined;
      if (!activeData) return;
      if (activeData.kind === "item") {
        const found = findItem(data, String(event.active.id));
        if (found) setActive({ kind: "item", item: found.item });
      } else if (activeData.kind === "column") {
        setActive({ kind: "column", columnId: activeData.columnId });
      }
    },
    [data, readOnly],
  );

  const onDragOver = useCallback(() => {
    // Visual rejection is handled inside SwimlaneCell via column.acceptsRendererIds + activeRendererId.
  }, []);

  const onDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active: a, over } = event;
      setActive(null);
      if (!over || readOnly) return;

      const activeData = a.data.current as
        | { kind: "item"; columnId: string; swimlaneId?: string; rendererId: string }
        | { kind: "column"; columnId: string }
        | undefined;
      const overData = over.data.current as
        | { kind: "item"; columnId: string; swimlaneId?: string; rendererId: string }
        | { kind: "cell"; columnId: string; swimlaneId?: string }
        | { kind: "collapsed-column"; columnId: string }
        | { kind: "column"; columnId: string }
        | undefined;
      if (!activeData || !overData) return;

      // ─── Column reorder ───
      if (activeData.kind === "column" && overData.kind === "column") {
        if (activeData.columnId === overData.columnId) return;
        const toIndex = data.columns.findIndex((c) => c.id === overData.columnId);
        if (toIndex < 0) return;
        dispatch({ type: "reorder-column", columnId: activeData.columnId, toIndex });
        return;
      }

      // ─── Item move ───
      if (activeData.kind !== "item") return;
      const itemId = String(a.id);
      const found = findItem(data, itemId);
      if (!found) return;

      let toColumnId: string | undefined;
      let toSwimlaneId: string | undefined;
      let toIndex = 0;

      if (overData.kind === "item") {
        const overFound = findItem(data, String(over.id));
        if (!overFound) return;
        toColumnId = overFound.columnId;
        toSwimlaneId = overData.swimlaneId;
        const targetCol = data.columns.find((c) => c.id === toColumnId);
        if (!targetCol) return;
        toIndex = targetCol.items.findIndex((it) => it.id === over.id);
        if (toIndex < 0) toIndex = targetCol.items.length;
      } else if (overData.kind === "cell" || overData.kind === "collapsed-column") {
        toColumnId = overData.columnId;
        toSwimlaneId = "swimlaneId" in overData ? overData.swimlaneId : undefined;
        const targetCol = data.columns.find((c) => c.id === toColumnId);
        if (!targetCol) return;
        toIndex = targetCol.items.length;
      } else {
        return;
      }

      const allowed = canDrop({
        data,
        itemId,
        fromColumnId: found.columnId,
        toColumnId,
        fromSwimlaneId: found.item.swimlaneId,
        toSwimlaneId,
        readOnly,
      });
      if (!allowed) return;

      // For same-column moves, adjust toIndex to handle the
      // active-before-over case correctly. When the active item sits before
      // the over item in the same column, removing the active first shifts
      // the over item's index down by 1; inserting at the original over
      // index would land the active *after* over, not at over's slot.
      if (toColumnId === found.columnId && found.index < toIndex) {
        toIndex = toIndex - 1;
      }

      // No-op when index doesn't actually change in the same column.
      if (
        toColumnId === found.columnId &&
        toIndex === found.index &&
        toSwimlaneId === found.item.swimlaneId
      ) {
        return;
      }

      // moveItem auto-expands collapsed target columns (locked contract baked
      // into the action so both controlled and uncontrolled modes apply it
      // atomically).
      dispatch({
        type: "move-item",
        itemId,
        toColumnId,
        toIndex,
        toSwimlaneId,
      });

      onItemMove?.(
        found.item,
        { columnId: found.columnId, swimlaneId: found.item.swimlaneId },
        { columnId: toColumnId, swimlaneId: toSwimlaneId },
      );
    },
    [data, dispatch, onItemMove, readOnly],
  );

  const onDragCancel = useCallback(() => {
    setActive(null);
  }, []);

  const activeItem = active?.kind === "item" ? active.item : null;
  const activeRendererId = active?.kind === "item" ? active.item.rendererId : undefined;

  return { onDragStart, onDragOver, onDragEnd, onDragCancel, activeItem, activeRendererId };
}

