export function ColumnHeader({
  column,
  palette,
  readOnly,
  itemCount,
  dragHandleProps,
  onColorChange,
  onCollapse,
  onEdit,
  onDelete,
}: {
  column: KanbanColumn;
  palette: KanbanPaletteSwatch[];
  readOnly: boolean;
  itemCount: number;
  dragHandleProps?: Record<string, unknown>;
  onColorChange: (color: string | undefined) => void;
  onCollapse: () => void;
  onEdit?: (column: KanbanColumn) => void;
  onDelete?: (columnId: string) => void;
}) {
  const showMenu = !readOnly && (onEdit || onDelete);
  const overCap = column.maxItems !== undefined && itemCount > column.maxItems;

  return (
    <div className="flex items-center gap-1 px-2.5 py-2">
      <div
        {...(readOnly ? {} : dragHandleProps)}
        className={cn(
          "flex min-w-0 flex-1 items-center gap-2",
          !readOnly && "cursor-grab active:cursor-grabbing",
        )}
      >
        <span className="truncate text-sm font-medium text-foreground">{column.title}</span>
        <span
          className={cn(
            "shrink-0 rounded-full bg-muted px-1.5 py-0.5 text-[10px] font-medium tabular-nums",
            overCap ? "bg-destructive/15 text-destructive" : "text-muted-foreground",
          )}
        >
          {column.maxItems !== undefined ? `${itemCount} / ${column.maxItems}` : itemCount}
        </span>
      </div>
      <div className="flex shrink-0 items-center" data-stop-click onPointerDown={(e) => e.stopPropagation()}>
        {!readOnly ? (
          <ColumnColorPicker
            palette={palette}
            current={column.color}
            onChange={onColorChange}
          />
        ) : null}
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="size-6"
          onClick={onCollapse}
          aria-label={`Collapse column ${column.title}`}
          data-stop-click
          onPointerDown={(e) => e.stopPropagation()}
        >
          <ChevronsLeft className="size-3.5" />
        </Button>
        {showMenu ? (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="size-6"
                aria-label="Column menu"
                data-stop-click
                onPointerDown={(e) => e.stopPropagation()}
              >
                <MoreHorizontal className="size-3.5" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              {onEdit ? (
                <DropdownMenuItem onClick={() => onEdit(column)}>
                  <Pencil className="size-3.5" />
                  Rename column
                </DropdownMenuItem>
              ) : null}
              {onEdit && onDelete ? <DropdownMenuSeparator /> : null}
              {onDelete ? (
                <DropdownMenuItem
                  onClick={() => onDelete(column.id)}
                  variant="destructive"
                >
                  <Trash2 className="size-3.5" />
                  Delete column
                </DropdownMenuItem>
              ) : null}
            </DropdownMenuContent>
          </DropdownMenu>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import type {
  AnyKanbanCardRenderer,
  KanbanColumn,
  KanbanItem,
  KanbanSwimlane,
} from "../types";
import { SwimlaneCell } from "./swimlane-cell";

export function ColumnBody({
  column,
  swimlanes,
  rendererMap,
  readOnly,
  activeRendererId,
  onItemClick,
  onItemDelete,
  onItemEdit,
}: {
  column: KanbanColumn;
  swimlanes: KanbanSwimlane[] | undefined;
  rendererMap: Map<string, AnyKanbanCardRenderer>;
  readOnly: boolean;
  activeRendererId: string | undefined;
  onItemClick?: (item: KanbanItem) => void;
  onItemDelete?: (itemId: string) => void;
  onItemEdit?: (item: KanbanItem) => void;
}) {
  // A drop is rejected if there's an active drag and this column doesn't accept that renderer.
  const rejectDrop =
    activeRendererId !== undefined &&
    column.acceptsRendererIds !== undefined &&
    !column.acceptsRendererIds.includes(activeRendererId);

  const lanes: (KanbanSwimlane | undefined)[] = swimlanes && swimlanes.length > 0 ? swimlanes : [undefined];

  return (
    <div className="flex-1 min-h-0 overflow-y-auto overflow-x-hidden px-1.5">
      <div className="flex flex-col gap-2 py-1.5">
        {lanes.map((lane) => {
          const items = column.items.filter((it) => {
            if (!swimlanes || swimlanes.length === 0) return true;
            // If item's swimlaneId is missing or unknown, it lands in the first lane.
            const known = swimlanes.some((l) => l.id === it.swimlaneId);
            if (!known) return lane?.id === swimlanes[0].id;
            return it.swimlaneId === lane?.id;
          });
          return (
            <div key={lane?.id ?? "_"} className="flex flex-col gap-1">
              {lane ? (
                <span className="px-1 text-[10px] font-medium uppercase tracking-wide text-muted-foreground/70">
                  {lane.title}
                </span>
              ) : null}
              <SwimlaneCell
                column={column}
                swimlaneId={lane?.id}
                items={items}
                rendererMap={rendererMap}
                readOnly={readOnly}
                rejectDrop={rejectDrop}
                onItemClick={onItemClick}
                onItemDelete={onItemDelete}
                onItemEdit={onItemEdit}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
}

